      '<h3>🔍 === Comparison Tests</h3>' +
      '<p style="color:#475569;font-size:0.82rem;font-style:italic">Add items to see comparison tests</p>';
    document.getElementById('broken-discount').style.display = 'none';
  } else {
    document.getElementById('fixed-cents').textContent   = '—';
    document.getElementById('fixed-display').textContent = '$0.00';
    document.getElementById('fixed-exact').textContent   = '—';
    document.getElementById('fixed-comparison').innerHTML =
      '<h3>🔍 Comparison Tests (cents)</h3>' +
      '<p style="color:#475569;font-size:0.82rem;font-style:italic">Add items to see comparison tests</p>';
    document.getElementById('fixed-discount').style.display = 'none';
  }
}

/* ═══════════════════════════════════════════
   LIVE PROOF PANEL
   Evaluate classic float gotchas right here
═══════════════════════════════════════════ */
function renderProof() {
  const proofs = [
    { expr: '0.1 + 0.2',           expected: 0.3   },
    { expr: '0.1 + 0.2 === 0.3',   expected: true  },
    { expr: '4.99 + 2.50 + 1.99',  expected: 9.48  },
    { expr: '(4.99+2.50+1.99) === 9.48', expected: true },
    { expr: '1.005.toFixed(2)',     expected: '"1.01"' },
    { expr: '0.3 - 0.1',           expected: 0.2   },
    { expr: '0.7 + 0.1',           expected: 0.8   },
    { expr: '0.1 * 3',             expected: 0.3   },
    { expr: '1.1 + 2.2',           expected: 3.3   },
    { expr: '0.2 + 0.4',           expected: 0.6   },
    { expr: '0.1 + 0.7',           expected: 0.8   },
    { expr: '3 * 0.1',             expected: 0.3   },
  ];

  // Safe evaluator
  function safeEval(expr) {
    try {
      // We only evaluate simple arithmetic expressions — safe here
      // eslint-disable-next-line no-new-func
      return Function(`"use strict"; return (${expr})`)();
    } catch(e) {
      return 'ERROR';
    }
  }

  const grid = document.getElementById('proof-grid');
  grid.innerHTML = '';

  proofs.forEach(p => {
    const actual   = safeEval(p.expr);
    const expected = p.expected;

    // Determine if the result matches what a naive developer would expect
    let matches;
    if (typeof expected === 'boolean') {
      matches = actual === expected;
    } else if (typeof expected === 'string') {
      matches = String(actual) === expected.replace(/"/g, '');
    } else {
      matches = actual === expected;
    }

    const actualStr = typeof actual === 'string'
      ? `"${actual}"`
      : String(actual);

    const div = document.createElement('div');
    div.className = 'proof-item';
    div.innerHTML = `
      <div class="expr">${p.expr}</div>
      <div class="actual ${matches ? 'right' : 'wrong'}">
        → ${actualStr}
        ${matches ? '✓ (as expected)' : `✗ expected: ${expected}`}
      </div>
    `;
    grid.appendChild(div);
  });
}

/* ═══════════════════════════════════════════
   INIT
═══════════════════════════════════════════ */
renderProducts();
renderProof();
</script>
