// DATA
// ─────────────────────────────────────────────────────────────────────────────

const PRESETS = [
    { icon: '☕', name: 'Coffee',       price: 4.99  },
    { icon: '🍕', name: 'Pizza Slice',  price: 3.49  },
    { icon: '📚', name: 'Notebook',     price: 7.99  },
    { icon: '🎧', name: 'Earbuds',      price: 19.99 },
    { icon: '🧴', name: 'Shampoo',      price: 5.49  },
    { icon: '🍫', name: 'Chocolate',    price: 2.99  },
    { icon: '🖊️', name: 'Pen Set',      price: 1.49  },
    { icon: '🧃', name: 'Juice Box',    price: 1.10  },  // 0.1 problem!
    { icon: '🥤', name: 'Soda',         price: 0.20  },  // 0.2 problem!
    { icon: '🍎', name: 'Apple',        price: 0.30  },  // 0.3 problem!
    { icon: '🧁', name: 'Cupcake',      price: 2.50  },
    { icon: '📦', name: 'Shipping',     price: 5.00  },
];

// ─────────────────────────────────────────────────────────────────────────────
// STATE
// ─────────────────────────────────────────────────────────────────────────────

// Each item: { id, name, price (float dollars) }
let cartItems = [];
let nextId = 1;

// ─────────────────────────────────────────────────────────────────────────────
// BROKEN MATH  (naive float)
// ─────────────────────────────────────────────────────────────────────────────

function brokenTotal(items) {
    // Just add floats directly — this is what the developer does
    let total = 0;
    for (const item of items) {
        total = total + item.price;   // accumulates IEEE 754 errors
    }
    return total;
}

function brokenEquals(a, b) {
    return a === b;   // exact bit comparison — often wrong for decimals
}

// ─────────────────────────────────────────────────────────────────────────────
// FIXED MATH  (integer cents)
// ─────────────────────────────────────────────────────────────────────────────

function toCents(dollars) {
    // Math.round avoids the 4.99 * 100 = 498.99999... problem
    return Math.round(dollars * 100);
}

function fixedTotal(items) {
    let totalCents = 0;
    for (const item of items) {
        totalCents += toCents(item.price);   // integer addition — exact
    }
    return totalCents;   // keep as integer cents
}

function centsToDisplay(cents) {
    return (cents / 100).toFixed(2);
}

function fixedEquals(centsA, centsB) {
    return centsA === centsB;   // integer === always works correctly
}

// ─────────────────────────────────────────────────────────────────────────────
// RENDER
// ─────────────────────────────────────────────────────────────────────────────

