    const brokenCountEl   = document.getElementById('brokenCount');
    const fixedCountEl    = document.getElementById('fixedCount');
    const brokenRawEl     = document.getElementById('brokenRaw');
    const fixedRawEl      = document.getElementById('fixedRaw');
    const brokenCompEl    = document.getElementById('brokenComparison');
    const fixedCompEl     = document.getElementById('fixedComparison');
    const brokenDiscEl    = document.getElementById('brokenDiscount');
    const fixedDiscEl     = document.getElementById('fixedDiscount');

    // ── Item Lists ──
