                <button class="remove-btn" onclick="removeItem(${item.id})" title="Remove">✕</button>
            </div>`).join('');

        fixedItemsEl.innerHTML = cartItems.map(item => `
            <div class="cart-item">
                <span class="cart-item-name">${escHtml(item.name)}</span>
                <span class="cart-item-price">${formatDollars(item.price)}
                    <span style="color:#475569;font-size:0.72rem">(${toCents(item.price)}¢)</span>
                </span>
                <button class="remove-btn" onclick="removeItem(${item.id})" title="Remove">✕</button>
            </div>`).join('');
    }

    // ── Totals ──
    const bTotal  = brokenTotal(cartItems);
    const fCents  = fixedTotal(cartItems);

    brokenCountEl.textContent = cartItems.length;
    fixedCountEl.textContent  = cartItems.length;

    brokenTotalEl.textContent = formatDollars(bTotal);
    fixedTotalEl.textContent  = '$' + centsToDisplay(fCents);

