    } else {
        brokenRawEl.textContent = '';
        fixedRawEl.textContent  = '';
    }

    // ── Comparison Panels ──
    if (cartItems.length >= 2) {
        // We'll check if the total "should" equal a round number near it
        const roundedBroken = parseFloat(bTotal.toFixed(2));
        const brokenEqCheck = brokenEquals(bTotal, roundedBroken);

        // For the fixed side, compute what the displayed cents "should" be
        const fixedDisplayCents = Math.round(parseFloat(centsToDisplay(fCents)) * 100);
        const fixedEqCheck      = fixedEquals(fCents, fixedDisplayCents);

        brokenCompEl.style.display = '';
        brokenCompEl.innerHTML = `
            <div class="comparison-title">❌ Equality Check (===)</div>
            <div class="code-line">floatTotal === parseFloat(floatTotal.toFixed(2))</div>
            <div class="code-line">${bTotal.toPrecision(17)} === ${roundedBroken}</div>
            <div class="result-line ${brokenEqCheck ? 'good' : 'bad'}">
