                ${brokenEqCheck ? '— (happened to match)' : '— ⚠️ Mismatch! Hidden precision error'}
            </div>`;

        fixedCompEl.style.display = '';
        fixedCompEl.innerHTML = `
            <div class="comparison-title">✅ Equality Check (integer cents)</div>
            <div class="code-line">totalCents === Math.round(display * 100)</div>
            <div class="code-line">${fCents} === ${fixedDisplayCents}</div>
            <div class="result-line good">
                Result: ${fixedEqCheck} — ✓ Always reliable
            </div>`;

        // ── Discount Panels ──
        const FREE_SHIPPING_CENTS = 5000;   // $50.00
        const FREE_SHIPPING_FLOAT = 50.00;

        brokenDiscEl.style.display = '';
        const brokenQualifies = bTotal >= FREE_SHIPPING_FLOAT;
