                <span class="label">Displayed total</span>
                <span>${formatDollars(bTotal)}</span>
            </div>`;

        fixedDiscEl.style.display = '';
        const fixedQualifies = fCents >= FREE_SHIPPING_CENTS;
        fixedDiscEl.innerHTML = `
            <h4>🚚 Free Shipping Check (≥ 5000¢)</h4>
            <div class="discount-row">
                <span class="label">Cart total (cents)</span>
                <span>${fCents}</span>
            </div>
            <div class="discount-row">
