                <span class="${fixedQualifies ? 'val-good' : 'val-bad'}">${fixedQualifies}</span>
            </div>
            <div class="discount-row">
                <span class="label">Displayed total</span>
                <span>$${centsToDisplay(fCents)}</span>
            </div>`;

    } else {
        brokenCompEl.style.display = 'none';
        fixedCompEl.style.display  = 'none';
        brokenDiscEl.style.display = 'none';
        fixedDiscEl.style.display  = 'none';
    }
}

