            actual:   (110 + 220 === 330),
            expected: true,
            raw:      `110 + 220 = ${110 + 220} (integer, exact)`,
            note:     '✅ Integer cents always work correctly.'
        },
        {
            expr:     'Math.round(0.1*100) + Math.round(0.2*100) === Math.round(0.3*100)',
            actual:   (Math.round(0.1*100) + Math.round(0.2*100) === Math.round(0.3*100)),
