            raw:      `10 + 20 === 30 → ${Math.round(0.1*100) + Math.round(0.2*100) === Math.round(0.3*100)}`,
            note:     '✅ Convert to cents first, then compare.'
        },
        {
            expr:     'parseFloat((0.1+0.2).toFixed(2)) === 0.30',
            actual:   (parseFloat((0.1+0.2).toFixed(2)) === 0.30),
            expected: true,
            raw:      `toFixed masks but doesn't fix the root`,
            note:     '⚠️ toFixed display trick — works here but fragile.'
        },
        {
            expr:     '19.99 * 3 === 59.97',
            actual:   (19.99 * 3 === 59.97),
            expected: true,
            raw:      `19.99 * 3 = ${(19.99 * 3).toPrecision(17)}`,
            note:     'Multiplication also accumulates errors.'
        },
    ];

    const el = document.getElementById('bugShowcase');
    el.innerHTML = cases.map(c => {
