        <div class="exp-block">
            <h3>🔴 The Problem: IEEE 754 Binary Floating Point</h3>
            <p>
                JavaScript (like most languages) stores decimal numbers in
                <strong>IEEE 754 double-precision binary format</strong>.
                Most decimal fractions <em>cannot be represented exactly</em>
                in binary — just like 1/3 cannot be written exactly in decimal.
            </p>
            <p>
                The number <code>0.1</code> in binary is actually
                <code>0.1000000000000000055511151231257827021181583404541015625</code>.
                When you add <code>0.1 + 0.2</code> you get
                <code>0.30000000000000004</code>, not <code>0.3</code>.
            </p>
            <p>
                Using <code>===</code> to compare two floats that should be equal
                will silently return <code>false</code> because the stored
                binary values differ by tiny fractions.
            </p>
            <pre><span class="highlight-comment">// ❌ Broken — looks right, is wrong</span>
let total = 0;
total += 4.99;   <span class="highlight-comment">// 4.99</span>
total += 2.50;   <span class="highlight-comment">// 7.49</span>
total += 1.01;   <span class="highlight-comment">// 8.50?</span>

<span class="highlight-comment">// Raw value: 8.500000000000002 !</span>
<span class="highlight-bad">total === 8.50  // false  ← silent bug!</span>

<span class="highlight-comment">// Classic JS gotcha</span>
<span class="highlight-bad">0.1 + 0.2 === 0.3  // false</span>
<span class="highlight-bad">1.005.toFixed(2)   // "1.00" not "1.01"</span></pre>
        </div>

        <div class="exp-block">
            <h3>🟢 The Fix: Integer Cents Arithmetic</h3>
            <p>
                The safest approach for money is to <strong>work entirely in
                integer cents</strong>. Integers are represented exactly in
                IEEE 754 up to 2<sup>53</sup>. Convert dollars → cents on
                input, do all math in cents, convert back only for display.
            </p>
            <p>
                Use <code>Math.round(price * 100)</code> to convert — never
                just <code>price * 100</code> alone, because that
                multiplication can itself introduce float error.
            </p>
            <pre><span class="highlight-comment">// ✅ Fixed — work in integer cents</span>
<span class="highlight-good">function toCents(dollars) {</span>
<span class="highlight-good">    return Math.round(dollars * 100);</span>
<span class="highlight-good">}</span>
<span class="highlight-good">function toDollars(cents) {</span>
<span class="highlight-good">    return (cents / 100).toFixed(2);</span>
<span class="highlight-good">}</span>

let totalCents = 0;
totalCents += toCents(4.99);  <span class="highlight-comment">// 499</span>
totalCents += toCents(2.50);  <span class="highlight-comment">// 250</span>
totalCents += toCents(1.01);  <span class="highlight-comment">// 101</span>
<span class="highlight-comment">// totalCents = 850  (exact integer)</span>

<span class="highlight-good">totalCents === 850   // true  ✓</span>
<span class="highlight-good">toDollars(totalCents) // "8.50" ✓</span>

<span class="highlight-comment">// Tax: round to nearest cent</span>
<span class="highlight-good">const taxCents =</span>
<span class="highlight-good">    Math.round(totalCents * 0.085);</span></pre>
        </div>

    </div>
</div>

<script>
// ─────────────────────────────────────────────────────────────────────────────
// PRODUCT DATA
// ─────────────────────────────────────────────────────────────────────────────
const PRODUCTS = [
    { id: 1, name: "☕ Coffee Mug",        price: 4.99  },
    { id: 2, name: "📓 Notebook",          price: 2.50  },
    { id: 3, name: "🖊 Fancy Pen",         price: 1.01  },
    { id: 4, name: "📎 Paperclip Pack",    price: 0.99  },
    { id: 5, name: "🗂 File Folder",       price: 3.75  },
    { id: 6, name: "🔦 Mini Flashlight",   price: 7.49  },
    { id: 7, name: "🧴 Hand Sanitizer",    price: 2.99  },
    { id: 8, name: "📏 Ruler",             price: 1.25  },
];

// Cart state
const brokenCart = [];   // stores raw float prices
const fixedCart  = [];   // stores integer cents

const TAX_RATE = 0.085;

// ─────────────────────────────────────────────────────────────────────────────
// CENTS HELPERS
// ─────────────────────────────────────────────────────────────────────────────
function toCents(dollars) {
    // Math.round guards against the float error in the multiplication itself
    return Math.round(dollars * 100);
}

function centsToDisplay(cents) {
    return "$" + (cents / 100).toFixed(2);
}

// ─────────────────────────────────────────────────────────────────────────────
// RENDER PRODUCT LISTS
// ─────────────────────────────────────────────────────────────────────────────
function renderProducts() {
    ["broken", "fixed"].forEach(mode => {
        const container = document.getElementById(`${mode}-products`);
        container.innerHTML = "";
        PRODUCTS.forEach(p => {
            const div = document.createElement("div");
            div.className = "product-item";
            div.innerHTML = `
                <span class="product-name">${p.name}</span>
                <span class="product-price">$${p.price.toFixed(2)}</span>
                <button class="add-btn" onclick="addItem('${mode}', ${p.id})">+ Add</button>
            `;
            container.appendChild(div);
        });
    });
}

// ─────────────────────────────────────────────────────────────────────────────
// ADD ITEM
// ─────────────────────────────────────────────────────────────────────────────
function addItem(mode, productId) {
    const product = PRODUCTS.find(p => p.id === productId);
    if (!product) return;

    if (mode === "broken") {
        brokenCart.push({ name: product.name, price: product.price });
        renderBrokenCart();
    } else {
        fixedCart.push({ name: product.name, cents: toCents(product.price) });
        renderFixedCart();
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// CLEAR CART
// ─────────────────────────────────────────────────────────────────────────────
function clearCart(mode) {
    if (mode === "broken") {
        brokenCart.length = 0;
        renderBrokenCart();
    } else {
        fixedCart.length = 0;
        renderFixedCart();
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// RENDER BROKEN CART
// ─────────────────────────────────────────────────────────────────────────────
function renderBrokenCart() {
    const itemsEl    = document.getElementById("broken-cart-items");
    const subEl      = document.getElementById("broken-subtotal");
    const subRawEl   = document.getElementById("broken-subtotal-raw");
    const taxEl      = document.getElementById("broken-tax");
    const taxRawEl   = document.getElementById("broken-tax-raw");
    const totalEl    = document.getElementById("broken-total");
    const totalRawEl = document.getElementById("broken-total-raw");
    const compEl     = document.getElementById("broken-comparison");

    if (brokenCart.length === 0) {
        itemsEl.innerHTML = '<span class="cart-empty">No items yet</span>';
        subEl.textContent = "$0.00";
        subRawEl.textContent = "";
        taxEl.textContent = "$0.00";
        taxRawEl.textContent = "";
        totalEl.textContent = "$0.00";
        totalRawEl.textContent = "";
        compEl.style.display = "none";
        return;
    }

    // Render item list
    itemsEl.innerHTML = brokenCart.map(item =>
        `<div class="cart-item">
            <span>${item.name}</span>
            <span>$${item.price.toFixed(2)}</span>
        </div>`
    ).join("");

    // ── BROKEN arithmetic: naive float addition ──
    let subtotal = 0;
    for (const item of brokenCart) {
        subtotal += item.price;   // ← raw float addition
    }

    const tax   = subtotal * TAX_RATE;   // ← raw float multiplication
    const total = subtotal + tax;

    // Display formatted
    subEl.textContent   = "$" + subtotal.toFixed(2);
    taxEl.textContent   = "$" + tax.toFixed(2);
    totalEl.textContent = "$" + total.toFixed(2);

    // Show raw JS value to reveal hidden precision errors
    const subRaw   = subtotal.toPrecision(20);
    const taxRaw   = tax.toPrecision(20);
    const totalRaw = total.toPrecision(20);

    subRawEl.textContent   = "raw: " + subRaw;
    taxRawEl.textContent   = "raw: " + taxRaw;
    totalRawEl.textContent = "raw: " + totalRaw;

    // Highlight if raw value differs from rounded display
    const subDisplay   = parseFloat(subtotal.toFixed(2));
    const totalDisplay = parseFloat(total.toFixed(2));

    subRawEl.style.color   = (subtotal !== subDisplay)   ? "#e53e3e" : "#aaa";
    totalRawEl.style.color = (total    !== totalDisplay) ? "#e53e3e" : "#aaa";

    // ── Comparison check ──
    // Simulate: "did the user pay exactly the right amount?"
    const expectedTotal = parseFloat(total.toFixed(2));
    const paidAmount    = total;   // pretend they paid the raw float value
    const strictEqual   = (paidAmount === expectedTotal);

    // A more dramatic demo: check if subtotal of specific combo equals known value
    const knownSubtotal = brokenCart.reduce((s, i) =>
        s + parseFloat(i.price.toFixed(2)), 0);
    const naiveCheck    = (subtotal === knownSubtotal);

    compEl.style.display = "block";
    if (subtotal !== subDisplay || !Number.isInteger(Math.round(subtotal * 100) / 100 * 100)) {
        compEl.className = "comparison-result fail";
        compEl.innerHTML = `
            ❌ <strong>Float precision error detected!</strong><br>
            <code>subtotal</code> raw = <code>${subRaw}</code><br>
            <code>subtotal === ${subDisplay}</code> → <strong>${subtotal === subDisplay}</strong><br>
            <small>toFixed(2) hides the error in display, but the stored value is wrong.</small>
        `;
    } else {
        compEl.className = "comparison-result pass";
        compEl.innerHTML = `
            ⚠️ <strong>No visible error yet</strong> — try adding more items with
            prices like $4.99, $1.01, $0.99 to trigger accumulation errors.
        `;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// RENDER FIXED CART
// ─────────────────────────────────────────────────────────────────────────────
function renderFixedCart() {
    const itemsEl    = document.getElementById("fixed-cart-items");
    const subEl      = document.getElementById("fixed-subtotal");
    const subRawEl   = document.getElementById("fixed-subtotal-raw");
    const taxEl      = document.getElementById("fixed-tax");
    const taxRawEl   = document.getElementById("fixed-tax-raw");
    const totalEl    = document.getElementById("fixed-total");
    const totalRawEl = document.getElementById("fixed-total-raw");
    const compEl     = document.getElementById("fixed-comparison");

    if (fixedCart.length === 0) {
        itemsEl.innerHTML = '<span class="cart-empty">No items yet</span>';
        subEl.textContent = "$0.00";
        subRawEl.textContent = "";
        taxEl.textContent = "$0.00";
        taxRawEl.textContent = "";
        totalEl.textContent = "$0.00";
        totalRawEl.textContent = "";
        compEl.style.display = "none";
        return;
    }

    // Render item list
    itemsEl.innerHTML = fixedCart.map(item =>
        `<div class="cart-item">
            <span>${item.name}</span>
            <span>${centsToDisplay(item.cents)}</span>
        </div>`
    ).join("");

    // ── FIXED arithmetic: integer cents ──
    let subtotalCents = 0;
    for (const item of fixedCart) {
        subtotalCents += item.cents;   // ← exact integer addition
    }

    // Tax: round to nearest cent
    const taxCents   = Math.round(subtotalCents * TAX_RATE);
    const totalCents = subtotalCents + taxCents;

    // Display
    subEl.textContent   = centsToDisplay(subtotalCents);
    taxEl.textContent   = centsToDisplay(taxCents);
    totalEl.textContent = centsToDisplay(totalCents);

    subRawEl.textContent   = `${subtotalCents} cents (exact integer)`;
    taxRawEl.textContent   = `${taxCents} cents (Math.round applied)`;
    totalRawEl.textContent = `${totalCents} cents (exact integer)`;

    // ── Comparison check ──
    // Integer comparison with === is always safe
    const expectedCents = totalCents;
    const paidCents     = totalCents;   // exact same integer
    const exactMatch    = (paidCents === expectedCents);

    compEl.style.display = "block";
    compEl.className = "comparison-result pass";
    compEl.innerHTML = `
        ✅ <strong>Integer comparison is exact!</strong><br>
        <code>totalCents === ${expectedCents}</code> → <strong>${exactMatch}</strong><br>
        <code>subtotalCents</code> = <code>${subtotalCents}</code> (no hidden decimals)<br>
        <small>All arithmetic stays in whole cents — no floating-point drift.</small>
    `;
}

// ─────────────────────────────────────────────────────────────────────────────
// LIVE DEMO
// ─────────────────────────────────────────────────────────────────────────────
function runDemo() {
    const a = parseFloat(document.getElementById("demoA").value) || 0;
    const b = parseFloat(document.getElementById("demoB").value) || 0;
    const out = document.getElementById("demoOutput");

    const floatSum   = a + b;
    const expected   = parseFloat((a + b).toFixed(2));
    const strictEq   = (floatSum === expected);

    const aCents     = toCents(a);
    const bCents     = toCents(b);
    const sumCents   = aCents + bCents;
    const centsEq    = (sumCents === toCents(a + b) || true);  // always integer

    // Show precision
    const rawStr = floatSum.toPrecision(20);
    const isExact = (rawStr === expected.toPrecision(20));

    out.innerHTML = `
<span class="info">── Broken Float Approach ──────────────────────</span>
<span class="bad">  ${a} + ${b} = ${floatSum} </span>
<span class="bad">  raw (20 sig figs): ${rawStr}</span>
<span class="bad">  ${floatSum} === ${expected}  →  ${strictEq}  ${strictEq ? "✓" : "← FAILS! toFixed hides it"}</span>
<span class="bad">  0.1 + 0.2 === 0.3  →  ${0.1 + 0.2 === 0.3}  (classic example)</span>

<span class="info">── Fixed Integer-Cents Approach ───────────────</span>
<span class="good">  toCents(${a}) = ${aCents}  |  toCents(${b}) = ${bCents}</span>
<span class="good">  ${aCents} + ${bCents} = ${sumCents} cents  (exact integer)</span>
<span class="good">  display: $${(sumCents / 100).toFixed(2)}</span>
<span class="good">  ${sumCents} === ${sumCents}  →  true  ✓ always exact</span>
    `.trim();
}

// ─────────────────────────────────────────────────────────────────────────────
// INIT
// ─────────────────────────────────────────────────────────────────────────────
renderProducts();
runDemo();
</script>
</body>
</html>
```

---

## What This File Demonstrates

### 🔴 The Core Problem
| Issue | Example |
|---|---|
| Binary can't store 0.1 exactly | `0.1` stored as `0.1000000000000000055...` |
| Addition accumulates error | `4.99 + 2.50 + 1.01 = 8.500000000000002` |
| `===` silently fails | `8.500000000000002 === 8.50` → **false** |
| `toFixed` hides the bug | Displays `"8.50"` but the stored value is wrong |

### 🟢 The Fix: Integer Cents
```js
// Always convert on input, never do math on raw floats
function toCents(dollars) { return Math.round(dollars * 100); }
// 499 + 250 + 101 = 850 (exact integer, === always works)
```

### Key Features
- **Live explorer** — type any two prices and see the raw 20-significant-figure value
- **Side-by-side carts** — add the same items to both and watch the raw values diverge
- **Inline code explanations** — shows exactly which line is broken vs fixed
- **Tax calculation** — shows how `Math.round` on cents handles the tax rounding correctly

