                <div class="checks" id="broken-checks"></div>

                <div class="action-btns">
                    <button class="btn btn-checkout" onclick="checkout('broken')">Checkout</button>
                    <button class="btn btn-clear"    onclick="clearCart('broken')">Clear</button>
                </div>
            </div>
        </div>

        <!-- ─── FIXED CART ─── -->
        <div class="cart-card">
            <div class="cart-header fixed-header">
                🟢 Fixed Cart
                <span class="badge">Integer Cents</span>
            </div>
            <div class="cart-body">
                <div class="products" id="fixed-products"></div>

                <div class="cart-items" id="fixed-items">
                    <div class="empty-msg">No items yet — add some above!</div>
                </div>

                <div class="totals-box">
                    <div class="total-row">
                        <span>Items:</span>
                        <span id="fixed-count">0</span>
                    </div>
                    <div class="total-row">
                        <span>Raw value (cents):</span>
                        <span id="fixed-raw" class="raw-value ok">0</span>
                    </div>
                    <div class="total-row grand">
                        <span>Total (displayed):</span>
                        <span id="fixed-total">$0.00</span>
                    </div>
                </div>

                <div class="checks" id="fixed-checks"></div>

                <div class="action-btns">
                    <button class="btn btn-checkout" onclick="checkout('fixed')">Checkout</button>
                    <button class="btn btn-clear"    onclick="clearCart('fixed')">Clear</button>
