</div><!-- end container -->

<!-- Toast -->
<div class="toast" id="toast"></div>

<script>
/* ═══════════════════════════════════════════════════════════════
   DATA
═══════════════════════════════════════════════════════════════ */
const PRODUCTS = [
    { name: '☕ Coffee',      price: 4.99 },
    { name: '🧁 Muffin',      price: 1.99 },
    { name: '🥤 Juice',       price: 2.49 },
    { name: '🥗 Salad',       price: 8.75 },
    { name: '🍕 Pizza Slice', price: 3.49 },
    { name: '🍫 Chocolate',   price: 1.49 },
    { name: '🥪 Sandwich',    price: 5.99 },
    { name: '💧 Water',       price: 0.99 },
];

/* Cart state */
const state = {
    broken: { items: [], floatTotal: 0 },
    fixed:  { items: [], centsTotal: 0 },
};

/* ═══════════════════════════════════════════════════════════════
   COMPARISON THRESHOLDS  (prices we test against)
═══════════════════════════════════════════════════════════════ */
const THRESHOLDS = [
    { label: 'Free shipping over $10.00', dollars: 10.00, cents: 1000 },
    { label: 'Discount coupon at $5.00',  dollars: 5.00,  cents:  500 },
    { label: 'Exact match $9.47',         dollars: 9.47,  cents:  947 },
];

/* ═══════════════════════════════════════════════════════════════
   INIT — build product buttons for both carts
═══════════════════════════════════════════════════════════════ */
function init() {
    ['broken', 'fixed'].forEach(side => {
        const container = document.getElementById(`${side}-products`);
        PRODUCTS.forEach(p => {
            const btn = document.createElement('button');
            btn.className = 'product-btn';
            btn.innerHTML = `
                <div class="p-name">${p.name}</div>
                <div class="p-price">$${p.price.toFixed(2)}</div>`;
            btn.onclick = () => addItem(side, p);
            container.appendChild(btn);
        });
    });
}

/* ═══════════════════════════════════════════════════════════════
   ADD ITEM
═══════════════════════════════════════════════════════════════ */
function addItem(side, product) {
    const item = { ...product, id: Date.now() + Math.random() };

    if (side === 'broken') {
        /* 🔴 BROKEN: plain float addition */
        const before = state.broken.floatTotal;
        state.broken.floatTotal += product.price;       // ← float error accumulates here
        state.broken.items.push(item);

        logLine('error',
            `[BROKEN] ${product.name}: ` +
            `${fmtFloat(before)} + ${product.price} = ` +
            `${fmtFloat(state.broken.floatTotal)}` +
            (state.broken.floatTotal !== parseFloat(state.broken.floatTotal.toFixed(2))
                ? '  ⚠ rounding error!' : ''));

    } else {
        /* 🟢 FIXED: convert to cents first, add integers */
        const priceCents = Math.round(product.price * 100);   // exact integer
        state.fixed.centsTotal += priceCents;
        state.fixed.items.push(item);

        logLine('success',
            `[FIXED]  ${product.name}: ` +
            `${priceCents}¢ added → total = ${state.fixed.centsTotal}¢ ` +
            `= $${(state.fixed.centsTotal / 100).toFixed(2)}  ✓`);
    }

    renderCart(side);
}

/* ═══════════════════════════════════════════════════════════════
   REMOVE ITEM
═══════════════════════════════════════════════════════════════ */
function removeItem(side, id) {
    if (side === 'broken') {
        const idx = state.broken.items.findIndex(i => i.id === id);
        if (idx === -1) return;
        const price = state.broken.items[idx].price;
        state.broken.floatTotal -= price;               // ← subtraction also accumulates error
        state.broken.items.splice(idx, 1);
        logLine('warn', `[BROKEN] Removed item → float total now: ${fmtFloat(state.broken.floatTotal)}`);
    } else {
        const idx = state.fixed.items.findIndex(i => i.id === id);
        if (idx === -1) return;
        const priceCents = Math.round(state.fixed.items[idx].price * 100);
        state.fixed.centsTotal -= priceCents;
        state.fixed.items.splice(idx, 1);
        logLine('info', `[FIXED]  Removed item → cents total now: ${state.fixed.centsTotal}¢`);
    }
    renderCart(side);
}

/* ═══════════════════════════════════════════════════════════════
   RENDER CART
═══════════════════════════════════════════════════════════════ */
function renderCart(side) {
    const isBroken = side === 'broken';
    const s        = isBroken ? state.broken : state.fixed;
    const items    = s.items;

    /* Items list */
    const listEl = document.getElementById(`${side}-items`);
    if (items.length === 0) {
        listEl.innerHTML = '<div class="empty-msg">No items yet — add some above!</div>';
    } else {
        listEl.innerHTML = items.map(item => `
            <div class="cart-item">
                <span class="item-name">${item.name}</span>
                <span class="item-price">$${item.price.toFixed(2)}</span>
                <button class="remove-btn" onclick="removeItem('${side}', ${item.id})">✕</button>
            </div>`).join('');
    }

    /* Count */
    document.getElementById(`${side}-count`).textContent = items.length;

    /* Raw value + displayed total */
    if (isBroken) {
        const raw = s.floatTotal;
        document.getElementById('broken-raw').textContent   = fmtFloat(raw);
        document.getElementById('broken-total').textContent = `$${raw.toFixed(2)}`;
        renderChecks('broken', raw, null);
    } else {
        const cents = s.centsTotal;
        document.getElementById('fixed-raw').textContent   = `${cents}¢`;
        document.getElementById('fixed-total').textContent = `$${(cents / 100).toFixed(2)}`;
        renderChecks('fixed', null, cents);
    }
}

/* ═══════════════════════════════════════════════════════════════
   RENDER COMPARISON CHECKS
═══════════════════════════════════════════════════════════════ */
function renderChecks(side, floatTotal, centsTotal) {
    const el = document.getElementById(`${side}-checks`);

    const rows = THRESHOLDS.map(t => {
        if (side === 'broken') {
            /* 🔴 Using === on floats — may fail due to rounding */
            const exactMatch = floatTotal === t.dollars;
            const gte        = floatTotal >= t.dollars;
            const pass       = gte;   // ">= check" usually works, but exact === often fails
            return buildCheckRow(
                pass,
                t.label,
                `floatTotal >= ${t.dollars}  →  ${floatTotal.toFixed(10)} >= ${t.dollars}  →  ${gte}`,
                exactMatch
                    ? null
                    : `(=== check: ${fmtFloat(floatTotal)} === ${t.dollars} → ${exactMatch})`
            );
        } else {
            /* 🟢 Integer cents — === always reliable */
            const exactMatch = centsTotal === t.cents;
            const gte        = centsTotal >= t.cents;
            return buildCheckRow(
                gte,
                t.label,
                `centsTotal >= ${t.cents}¢  →  ${centsTotal} >= ${t.cents}  →  ${gte}`,
                null
            );
        }
    });

    el.innerHTML = rows.join('');
}

function buildCheckRow(pass, label, detail, warning) {
    return `
        <div class="check-row ${pass ? 'pass' : 'fail'}">
            <span class="check-icon">${pass ? '✅' : '❌'}</span>
            <div>
                <div class="check-label">${label}</div>
                <div class="check-detail">${detail}</div>
                ${warning ? `<div class="check-detail" style="color:#e74c3c">${warning}</div>` : ''}
            </div>
        </div>`;
}

/* ═══════════════════════════════════════════════════════════════
   CHECKOUT
═══════════════════════════════════════════════════════════════ */
function checkout(side) {
    const isBroken = side === 'broken';
    const s        = isBroken ? state.broken : state.fixed;

    if (s.items.length === 0) {
        showToast('Your cart is empty!', 'info');
        return;
    }

    if (isBroken) {
        const raw       = s.floatTotal;
        const displayed = raw.toFixed(2);
        const hasError  = raw !== parseFloat(displayed);

        logLine('warn',
            `[BROKEN] Checkout: raw=${fmtFloat(raw)}, displayed=$${displayed}, ` +
            `hasHiddenError=${hasError}`);

        if (hasError) {
            showToast(
                `⚠️ Float error! Raw: ${fmtFloat(raw)} | Shown: $${displayed}`,
                'error'
            );
        } else {
            showToast(`Broken cart checkout: $${displayed} (lucky — no visible error this time)`, 'info');
        }
    } else {
        const cents = s.centsTotal;
        logLine('success',
            `[FIXED]  Checkout: ${cents}¢ = $${(cents/100).toFixed(2)} (exact integer, no error)`);
        showToast(`✅ Fixed cart checkout: $${(cents/100).toFixed(2)} (exact!)`, 'success');
    }
}

/* ═══════════════════════════════════════════════════════════════
   CLEAR CART
═══════════════════════════════════════════════════════════════ */
function clearCart(side) {
    if (side === 'broken') {
        state.broken.items      = [];
        state.broken.floatTotal = 0;
    } else {
        state.fixed.items       = [];
        state.fixed.centsTotal  = 0;
    }
    renderCart(side);
    logLine('dim', `[${side.toUpperCase()}] Cart cleared.`);
}

/* ═══════════════════════════════════════════════════════════════
   CONSOLE HELPERS
═══════════════════════════════════════════════════════════════ */
function logLine(type, msg) {
    const box  = document.getElementById('console-box');
    const line = document.createElement('div');
    line.className = `log-line log-${type}`;
    const ts = new Date().toLocaleTimeString('en-US', { hour12: false });
    line.textContent = `[${ts}] ${msg}`;
    box.appendChild(line);
    box.scrollTop = box.scrollHeight;
}

function clearConsole() {
    const box = document.getElementById('console-box');
    box.innerHTML = '<div class="log-line log-dim">// Console cleared.</div>';
}

/* ═══════════════════════════════════════════════════════════════
   TOAST
═══════════════════════════════════════════════════════════════ */
let toastTimer;
function showToast(msg, type = 'info') {
    const el = document.getElementById('toast');
    el.textContent  = msg;
    el.className    = `toast ${type} show`;
    clearTimeout(toastTimer);
    toastTimer = setTimeout(() => { el.className = 'toast'; }, 3500);
}

/* ═══════════════════════════════════════════════════════════════
   UTILITY
═══════════════════════════════════════════════════════════════ */
/* Show full float precision so rounding errors are visible */
function fmtFloat(n) {
    /* toPrecision(15) exposes the hidden digits */
    return parseFloat(n.toPrecision(15)).toString();
}

/* ═══════════════════════════════════════════════════════════════
   BOOTSTRAP
═══════════════════════════════════════════════════════════════ */
init();

/* Log a quick demo on load so the console isn't empty */
(function demoLog() {
    logLine('dim', '// ── Quick Demo ──────────────────────────────────');
    logLine('error',
        '[BROKEN] 0.1 + 0.2 = ' + (0.1 + 0.2) +
        '  (expected 0.3, got ' + (0.1 + 0.2) + ')');
    logLine('error',
        '[BROKEN] (0.1 + 0.2) === 0.3  →  ' + ((0.1 + 0.2) === 0.3));
    logLine('success',
        '[FIXED]  10 + 20 = ' + (10 + 20) + '¢  →  (10 + 20) === 30  →  ' + ((10 + 20) === 30));
    logLine('dim', '// ─────────────────────────────────────────────────');
    logLine('dim', '// Add items to both carts to see live differences...');
})();
</script>
</body>
