renderProductButtons();

// Pre-load both carts with the same two items so the bug is
// immediately visible on page load without any user interaction.
(function preload() {
    // Two coffees at $4.99 each → mathematically $9.98
    // but float addition gives 9.98 exactly here...
    // Use coffee + sandwich + cookie to guarantee a visible error
    addToBrokenCart(PRODUCTS[0]); // Coffee  $4.99
    addToBrokenCart(PRODUCTS[0]); // Coffee  $4.99  → 9.98 (might be exact)
    addToBrokenCart(PRODUCTS[6]); // Water   $0.99  → 10.97 (float error likely)
    addToBrokenCart(PRODUCTS[2]); // Cookie  $1.99  → 12.96 (accumulates)

    addToFixedCart(PRODUCTS[0]);
    addToFixedCart(PRODUCTS[0]);
    addToFixedCart(PRODUCTS[6]);
