<span class="code-keyword">const</span> toDollars = cents => (cents / <span class="code-number">100</span>).toFixed(<span class="code-number">2</span>); <span class="code-comment">// 499 → "4.99"</span>

<span class="code-keyword">let</span> totalCents = <span class="code-number">0</span>;
cart.forEach(item => totalCents += toCents(item.price)); <span class="code-comment">// exact integers</span>

<span class="code-keyword">const</span> taxCents = Math.round(totalCents * <span class="code-number">0.085</span>);   <span class="code-comment">// round to nearest cent</span>
<span class="code-keyword">const</span> grandTotalCents = totalCents + taxCents;     <span class="code-comment">// exact integer addition</span>

<span class="code-good">grandTotalCents === expectedCents                   // ✓ RELIABLE</span>
<span class="code-good">toCents(0.1) + toCents(0.2) === toCents(0.3)       // true (10 + 20 === 30)</span>
<span class="code-good">toDollars(grandTotalCents)                          // always correct display</span>
    </div>

