<script>
    // ─────────────────────────────────────────────────────────────────────────
    // SHARED DATA
    // ─────────────────────────────────────────────────────────────────────────
    const PRODUCTS = [
        { name: "Coffee",      price: 4.99  },
        { name: "Sandwich",    price: 7.49  },
        { name: "Cookie",      price: 2.99  },
        { name: "Juice",       price: 3.49  },
        { name: "Salad",       price: 8.99  },
        { name: "Water",       price: 1.29  },
        { name: "Muffin",      price: 3.75  },
        { name: "Wrap",        price: 6.49  },
    ];

    const TAX_RATE = 0.085;

    // ─────────────────────────────────────────────────────────────────────────
    // UTILITY: Integer cents helpers
    // ─────────────────────────────────────────────────────────────────────────
    const toCents   = price  => Math.round(price * 100);
    const toDollars = cents  => (cents / 100).toFixed(2);

    // ─────────────────────────────────────────────────────────────────────────
    // STATE
    // ─────────────────────────────────────────────────────────────────────────
    let brokenCart = [];  // stores raw floats
    let fixedCart  = [];  // stores integer cents

    // ─────────────────────────────────────────────────────────────────────────
    // BUILD PRODUCT BUTTONS
    // ─────────────────────────────────────────────────────────────────────────
    function buildProductButtons() {
        const brokenContainer = document.getElementById('broken-products');
        const fixedContainer  = document.getElementById('fixed-products');

        PRODUCTS.forEach((p, i) => {
            const makeBtn = (container, clickFn) => {
                const btn = document.createElement('button');
                btn.className = 'product-btn';
                btn.innerHTML = `
                    <span class="p-name">${p.name}</span>
                    <span class="p-price">$${p.price.toFixed(2)}</span>
                `;
                btn.addEventListener('click', () => clickFn(i));
                container.appendChild(btn);
            };
            makeBtn(brokenContainer, addToBrokenCart);
            makeBtn(fixedContainer,  addToFixedCart);
        });
    }

    // ─────────────────────────────────────────────────────────────────────────
    // BROKEN CART — uses raw float addition
    // ─────────────────────────────────────────────────────────────────────────
    function addToBrokenCart(productIndex) {
        brokenCart.push({ ...PRODUCTS[productIndex] });
        renderBrokenCart();
    }

    function removeFromBrokenCart(index) {
        brokenCart.splice(index, 1);
        renderBrokenCart();
    }

    function clearBrokenCart() {
        brokenCart = [];
        renderBrokenCart();
    }

    function renderBrokenCart() {
        const cartEl = document.getElementById('broken-cart');

        if (brokenCart.length === 0) {
            cartEl.innerHTML = '<div class="empty-cart">Cart is empty — add some items!</div>';
        } else {
            cartEl.innerHTML = brokenCart.map((item, i) => `
                <div class="cart-item">
                    <span class="cart-item-name">${item.name}</span>
                    <span class="cart-item-price">$${item.price.toFixed(2)}</span>
                    <button class="remove-btn" onclick="removeFromBrokenCart(${i})">✕</button>
                </div>
            `).join('');
        }

        // ── BROKEN arithmetic: plain float addition ──
        let subtotal = 0;
        brokenCart.forEach(item => {
            subtotal += item.price;   // ← drift happens here
        });

        const tax        = subtotal * TAX_RATE;
        const grandTotal = subtotal + tax;

        // Display with toFixed for readability, but show raw to expose drift
        document.getElementById('broken-subtotal').textContent     = `$${subtotal.toFixed(2)}`;
        document.getElementById('broken-subtotal-raw').textContent = `raw: ${subtotal}`;
        document.getElementById('broken-tax').textContent          = `$${tax.toFixed(2)}`;
        document.getElementById('broken-tax-raw').textContent      = `raw: ${tax}`;
        document.getElementById('broken-total').textContent        = `$${grandTotal.toFixed(2)}`;
        document.getElementById('broken-total-raw').textContent    = `raw: ${grandTotal}`;

        // ── Broken comparisons ──
        const comp1Result = (4.99 + 2.99) === 7.98;
        document.getElementById('broken-comp-1').textContent  = comp1Result ? 'TRUE ✓' : 'FALSE ✗';
        document.getElementById('broken-comp-1').className    = comp1Result ? 'result-pass' : 'result-fail';

        // Compute "expected" total the same broken way — still may not match
        // due to different addition order
        const expectedTotal = brokenCart.reduce((s, item) => s + item.price, 0) * (1 + TAX_RATE);
        const comp2Result   = grandTotal === expectedTotal;
        document.getElementById('broken-comp-2').textContent  = comp2Result ? 'TRUE ✓' : `FALSE ✗ (${grandTotal} ≠ ${expectedTotal})`;
        document.getElementById('broken-comp-2').className    = comp2Result ? 'result-pass' : 'result-fail';
    }

    function checkBrokenDiscount() {
        const threshold = parseFloat(document.getElementById('broken-threshold').value);
        const resultEl  = document.getElementById('broken-discount-result');

        if (brokenCart.length === 0) {
            resultEl.className   = 'discount-result neutral';
            resultEl.textContent = 'Add items to check discount eligibility';
            return;
        }

        // Broken: raw float addition then ===
        let subtotal = 0;
        brokenCart.forEach(item => subtotal += item.price);
        const tax        = subtotal * TAX_RATE;
        const grandTotal = subtotal + tax;

        const exactMatch = grandTotal === threshold;
        const rawInfo    = `(raw total: ${grandTotal}, target: ${threshold})`;

        if (exactMatch) {
            resultEl.className   = 'discount-result pass';
            resultEl.textContent = `✓ Discount applied! Total exactly matches $${threshold.toFixed(2)} ${rawInfo}`;
        } else {
            resultEl.className   = 'discount-result fail';
            resultEl.textContent = `✗ No discount — === comparison failed even if values look equal! ${rawInfo}`;
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // FIXED CART — uses integer cents
    // ─────────────────────────────────────────────────────────────────────────
    function addToFixedCart(productIndex) {
        const product = PRODUCTS[productIndex];
        fixedCart.push({
            name:  product.name,
            price: product.price,          // keep original for display
            cents: toCents(product.price), // integer cents for arithmetic
        });
        renderFixedCart();
    }

    function removeFromFixedCart(index) {
        fixedCart.splice(index, 1);
        renderFixedCart();
    }

    function clearFixedCart() {
        fixedCart = [];
        renderFixedCart();
    }

    function renderFixedCart() {
        const cartEl = document.getElementById('fixed-cart');

        if (fixedCart.length === 0) {
            cartEl.innerHTML = '<div class="empty-cart">Cart is empty — add some items!</div>';
        } else {
            cartEl.innerHTML = fixedCart.map((item, i) => `
                <div class="cart-item">
                    <span class="cart-item-name">${item.name}</span>
                    <span class="cart-item-price">$${toDollars(item.cents)}</span>
                    <button class="remove-btn" onclick="removeFromFixedCart(${i})">✕</button>
                </div>
            `).join('');
        }

        // ── FIXED arithmetic: integer cents addition ──
        let subtotalCents = 0;
        fixedCart.forEach(item => {
            subtotalCents += item.cents;   // exact integer addition
        });

        const taxCents        = Math.round(subtotalCents * TAX_RATE); // round to nearest cent
        const grandTotalCents = subtotalCents + taxCents;

        document.getElementById('fixed-subtotal').textContent     = `$${toDollars(subtotalCents)}`;
        document.getElementById('fixed-subtotal-raw').textContent = `cents: ${subtotalCents}`;
        document.getElementById('fixed-tax').textContent          = `$${toDollars(taxCents)}`;
        document.getElementById('fixed-tax-raw').textContent      = `cents: ${taxCents}`;
        document.getElementById('fixed-total').textContent        = `$${toDollars(grandTotalCents)}`;
        document.getElementById('fixed-total-raw').textContent    = `cents: ${grandTotalCents}`;

        // ── Fixed comparisons ──
        const comp1Result = (toCents(4.99) + toCents(2.99)) === toCents(7.98);
        document.getElementById('fixed-comp-1').textContent = comp1Result ? 'TRUE ✓' : 'FALSE ✗';
        document.getElementById('fixed-comp-1').className   = comp1Result ? 'result-pass' : 'result-fail';

        // Recompute expected total using same integer method
        const expectedCents = fixedCart.reduce((s, item) => s + item.cents, 0);
        const expTax        = Math.round(expectedCents * TAX_RATE);
        const expGrand      = expectedCents + expTax;
        const comp2Result   = grandTotalCents === expGrand;
        document.getElementById('fixed-comp-2').textContent = comp2Result ? 'TRUE ✓' : `FALSE ✗`;
        document.getElementById('fixed-comp-2').className   = comp2Result ? 'result-pass' : 'result-fail';
    }

    function checkFixedDiscount() {
        const threshold    = parseFloat(document.getElementById('fixed-threshold').value);
        const threshCents  = toCents(threshold);
        const resultEl     = document.getElementById('fixed-discount-result');

        if (fixedCart.length === 0) {
            resultEl.className   = 'discount-result neutral';
            resultEl.textContent = 'Add items to check discount eligibility';
            return;
        }

        let subtotalCents = 0;
        fixedCart.forEach(item => subtotalCents += item.cents);
        const taxCents        = Math.round(subtotalCents * TAX_RATE);
        const grandTotalCents = subtotalCents + taxCents;

        // Fixed: compare integer cents with ===
        const exactMatch = grandTotalCents === threshCents;
        const rawInfo    = `(${grandTotalCents} cents vs ${threshCents} cents)`;

        if (exactMatch) {
            resultEl.className   = 'discount-result pass';
            resultEl.textContent = `✓ Discount applied! Integer cents match exactly! ${rawInfo}`;
        } else {
            resultEl.className   = 'discount-result fail';
            resultEl.textContent = `✗ No discount — total ${grandTotalCents}¢ ≠ ${threshCents}¢ ${rawInfo}`;
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // LIVE DEMO EXAMPLES
    // ─────────────────────────────────────────────────────────────────────────
    function buildLiveExamples() {
        const examples = [
            {
                expr:     '0.1 + 0.2 === 0.3',
                result:   0.1 + 0.2 === 0.3,
                expected: false,
                note:     `actual: ${0.1 + 0.2}`,
            },
            {
                expr:     '4.99 + 2.99 === 7.98',
                result:   4.99 + 2.99 === 7.98,
                expected: false,
