<span class="code-comment">// ❌ BROKEN: Raw float arithmetic — DO NOT USE FOR MONEY</span>

<span class="code-keyword">const</span> price1 = <span class="code-number">4.99</span>;   <span class="code-comment">// stored as 4.990000000000000213162820728...</span>
<span class="code-keyword">const</span> price2 = <span class="code-number">3.99</span>;   <span class="code-comment">// stored as 3.990000000000000213162820728...</span>
<span class="code-keyword">const</span> price3 = <span class="code-number">1.01</span>;   <span class="code-comment">// stored as 1.010000000000000008881784197...</span>

<span class="code-keyword">const</span> total = price1 + price2 + price3;
<span class="code-function">console</span>.<span class="code-function">log</span>(total);           <span class="code-comment">// 9.989999999999999 ← NOT 9.99!</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(total === <span class="code-number">9.99</span>);  <span class="code-bad">// false ← discount code never applies!</span>

<span class="code-comment">// Classic JavaScript float traps:</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.1</span> + <span class="code-number">0.2</span>);           <span class="code-comment">// 0.30000000000000004</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.1</span> + <span class="code-number">0.2</span> === <span class="code-number">0.3</span>); <span class="code-bad">// false</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">1.005</span>.<span class="code-function">toFixed</span>(<span class="code-number">2</span>));    <span class="code-comment">// "1.00" ← rounds wrong! (should be 1.01)</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.3</span> - <span class="code-number">0.2</span> === <span class="code-number">0.1</span>); <span class="code-bad">// false</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-number">0.7</span> + <span class="code-number">0.1</span> === <span class="code-number">0.8</span>); <span class="code-bad">// false</span>

<span class="code-comment">// Tax calculation nightmare:</span>
<span class="code-keyword">const</span> subtotal = <span class="code-number">19.99</span>;
