<span class="code-keyword">const</span> toCents  = (<span class="code-keyword">dollars</span>) => <span class="code-function">Math</span>.<span class="code-function">round</span>(dollars * <span class="code-number">100</span>);
<span class="code-keyword">const</span> toDollars = (<span class="code-keyword">cents</span>)   => (cents / <span class="code-number">100</span>).<span class="code-function">toFixed</span>(<span class="code-number">2</span>);

<span class="code-keyword">const</span> price1 = <span class="code-function">toCents</span>(<span class="code-number">4.99</span>);  <span class="code-comment">// 499  ← exact integer!</span>
<span class="code-keyword">const</span> price2 = <span class="code-function">toCents</span>(<span class="code-number">3.99</span>);  <span class="code-comment">// 399  ← exact integer!</span>
<span class="code-keyword">const</span> price3 = <span class="code-function">toCents</span>(<span class="code-number">1.01</span>);  <span class="code-comment">// 101  ← exact integer!</span>

<span class="code-keyword">const</span> totalCents = price1 + price2 + price3;  <span class="code-comment">// 999 ← exact!</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(totalCents === <span class="code-number">999</span>);              <span class="code-good">// true ← discount applies!</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(<span class="code-function">toDollars</span>(totalCents));           <span class="code-comment">// "9.99" ← correct display</span>

<span class="code-comment">// Safe tax calculation (round at the end, once):</span>
<span class="code-keyword">const</span> subtotalCents = <span class="code-number">1999</span>;
<span class="code-keyword">const</span> taxRateBps    = <span class="code-number">850</span>;   <span class="code-comment">// 8.50% in basis points (850/10000)</span>
<span class="code-keyword">const</span> taxCents      = <span class="code-function">Math</span>.<span class="code-function">round</span>(subtotalCents * taxRateBps / <span class="code-number">10000</span>);
<span class="code-function">console</span>.<span class="code-function">log</span>(taxCents);                         <span class="code-comment">// 170 ← exactly $1.70</span>

<span class="code-comment">// Comparison is now === safe because integers are exact:</span>
<span class="code-keyword">const</span> targetCents = <span class="code-function">toCents</span>(<span class="code-number">9.99</span>);  <span class="code-comment">// 999</span>
<span class="code-function">console</span>.<span class="code-function">log</span>(totalCents === targetCents);       <span class="code-good">// true ✅</span>
                </div>

