<script>
// ─────────────────────────────────────────────
//  DATA
// ─────────────────────────────────────────────
const PRODUCTS = [
  { name: "Coffee",    priceCents: 499  },  // $4.99
  { name: "Sandwich",  priceCents: 799  },  // $7.99
  { name: "Juice",     priceCents: 299  },  // $2.99
  { name: "Muffin",    priceCents: 349  },  // $3.49
  { name: "Salad",     priceCents: 899  },  // $8.99
  { name: "Water",     priceCents: 150  },  // $1.50
  { name: "Chips",     priceCents: 179  },  // $1.79
  { name: "Yoghurt",   priceCents: 249  },  // $2.49
];

// Cart state: each entry { name, priceCents, qty }
const carts = {
  broken: [],
  fixed:  []
};

// ─────────────────────────────────────────────
//  FLOAT VISUALISER  (rendered once on load)
// ─────────────────────────────────────────────
const floatExamples = [
  {
    expr:    "0.1 + 0.2",
    actual:  0.1 + 0.2,
    compare: 0.3,
    label:   "=== 0.3"
  },
  {
    expr:    "4.99 + 2.99",
    actual:  4.99 + 2.99,
    compare: 7.98,
    label:   "=== 7.98"
  },
  {
    expr:    "1.79 + 2.49 + 1.50",
    actual:  1.79 + 2.49 + 1.50,
    compare: 5.78,
    label:   "=== 5.78"
  },
  {
    expr:    "4.99+2.99+1.99",
    actual:  4.99 + 2.99 + 1.99,
    compare: 9.97,
    label:   "=== 9.97"
  },
  {
    expr:    "8.99 + 3.49 + 1.79",
    actual:  8.99 + 3.49 + 1.79,
    compare: 14.27,
    label:   "=== 14.27"
  },
  {
    expr:    "2.49 * 3",
    actual:  2.49 * 3,
    compare: 7.47,
    label:   "=== 7.47"
  },
  {
    expr:    "7.99 - 2.99",
    actual:  7.99 - 2.99,
    compare: 5.00,
    label:   "=== 5.00"
  },
  {
    expr:    "1.50 * 4",
    actual:  1.50 * 4,
    compare: 6.00,
    label:   "=== 6.00"
  },
];

function buildFloatGrid() {
  const grid = document.getElementById('floatGrid');
  floatExamples.forEach(ex => {
    const passes = (ex.actual === ex.compare);
    const card = document.createElement('div');
    card.className = 'float-card';
    card.innerHTML = `
      <div class="expr">${ex.expr}</div>
      <div class="result">Result: ${ex.actual.toPrecision(17)}</div>
      <div class="result">Expected: ${ex.compare}</div>
      <div class="result">toFixed(2): "${ex.actual.toFixed(2)}"</div>
      <span class="verdict ${passes ? 'verdict-pass' : 'verdict-fail'}">
        ${ex.label} → ${passes ? 'true ✓' : 'false ✗'}
      </span>
    `;
    grid.appendChild(card);
  });
}

// ─────────────────────────────────────────────
//  BUILD PRODUCT BUTTONS
// ─────────────────────────────────────────────
function buildProductButtons() {
  ['broken', 'fixed'].forEach(side => {
    const grid = document.getElementById(side + 'Products');
    PRODUCTS.forEach(p => {
      const btn = document.createElement('button');
      btn.className = 'product-btn';
      btn.innerHTML = `
        <div class="pname">${p.name}</div>
        <div class="pprice">$${(p.priceCents / 100).toFixed(2)}</div>
      `;
      btn.addEventListener('click', () => addToCart(side, p));
      grid.appendChild(btn);
    });
  });
}

// ─────────────────────────────────────────────
//  CART OPERATIONS
// ─────────────────────────────────────────────
function addToCart(side, product) {
  const existing = carts[side].find(i => i.name === product.name);
  if (existing) {
    existing.qty++;
  } else {
    carts[side].push({ name: product.name, priceCents: product.priceCents, qty: 1 });
  }
  renderCart(side);
}

function removeFromCart(side, name) {
  const idx = carts[side].findIndex(i => i.name === name);
  if (idx === -1) return;
  if (carts[side][idx].qty > 1) {
    carts[side][idx].qty--;
  } else {
    carts[side].splice(idx, 1);
  }
  renderCart(side);
}

function clearCart(side) {
  carts[side] = [];
  renderCart(side);
}

// ─────────────────────────────────────────────
//  RENDER
// ─────────────────────────────────────────────
function renderCart(side) {
  const cart = carts[side];
  const itemsEl = document.getElementById(side + 'Items');

  // Items list
  if (cart.length === 0) {
    itemsEl.innerHTML = '<p class="empty-cart">Cart is empty — add items above</p>';
  } else {
    itemsEl.innerHTML = cart.map(item => {
      const lineTotal = (item.priceCents * item.qty / 100).toFixed(2);
      return `
        <div class="cart-item">
          <span class="iname">${item.name}</span>
          <span class="iqty">×${item.qty}</span>
          <span class="iprice">$${lineTotal}</span>
          <button class="remove-btn" onclick="removeFromCart('${side}','${item.name}')">−</button>
        </div>
      `;
    }).join('');
  }

  if (side === 'broken') renderBrokenTotals();
  else                   renderFixedTotals();
}

// ── BROKEN: sum floats directly ──
function renderBrokenTotals() {
  const cart = carts.broken;

  // Build float sum the "naive" way
  let floatTotal = 0;
  cart.forEach(item => {
    for (let i = 0; i < item.qty; i++) {
      floatTotal += item.priceCents / 100;   // convert each time — maximises error
    }
  });

  document.getElementById('brokenRaw').textContent   = '$' + floatTotal;
  document.getElementById('brokenFixed').textContent = '$' + floatTotal.toFixed(2);
  document.getElementById('brokenFull').textContent  = floatTotal.toPrecision(17);

  renderBrokenComparisons(floatTotal);
}

function renderBrokenComparisons(floatTotal) {
  const raw = parseFloat(document.getElementById('brokenThreshold').value) || 0;
  const box = document.getElementById('brokenComparisons');

  const tripleEq    = floatTotal === raw;
  const toFixedEq   = floatTotal.toFixed(2) === raw.toFixed(2);
  const mathRoundEq = Math.round(floatTotal * 100) === Math.round(raw * 100);

  box.innerHTML = `
    <div class="cline">
      <span class="cexpr">total === ${raw}</span>
      <span class="cres ${tripleEq ? 'pass' : 'fail'}">${tripleEq} ${tripleEq ? '✓' : '✗'}</span>
    </div>
    <div class="cline">
      <span class="cexpr">toFixed(2) string ===</span>
      <span class="cres ${toFixedEq ? 'pass' : 'fail'}">${toFixedEq} ${toFixedEq ? '✓' : '⚠'}</span>
    </div>
    <div class="cline">
      <span class="cexpr">Math.round(*100) ===</span>
      <span class="cres ${mathRoundEq ? 'pass' : 'fail'}">${mathRoundEq} ${mathRoundEq ? '✓' : '✗'}</span>
    </div>
    <div style="margin-top:6px;color:#555;font-size:0.72rem;">
      Internal value: ${floatTotal.toPrecision(17)}
    </div>
  `;
}

// ── FIXED: sum integer cents ──
function renderFixedTotals() {
  const cart = carts.fixed;

  // Integer sum — ZERO rounding error
  let centsTotal = 0;
  cart.forEach(item => {
    centsTotal += item.priceCents * item.qty;  // integer × integer
  });

  const dollarsExact = centsTotal / 100;

  document.getElementById('fixedCents').textContent   = centsTotal + '¢';
  document.getElementById('fixedDollars').textContent = '$' + dollarsExact.toFixed(2);
  document.getElementById('fixedFull').textContent    = dollarsExact.toPrecision(17);

  renderFixedComparisons(centsTotal);
}

function renderFixedComparisons(centsTotal) {
  const raw = parseFloat(document.getElementById('fixedThreshold').value) || 0;
  // Convert threshold to cents (integer)
  const threshCents = Math.round(raw * 100);

  const intEq     = centsTotal === threshCents;
  const floatDisp = centsTotal / 100;
  const floatEq   = floatDisp === raw;  // still risky — shown for comparison

  const box = document.getElementById('fixedComparisons');
  box.innerHTML = `
    <div class="cline">
      <span class="cexpr">centsTotal === ${threshCents}¢</span>
      <span class="cres ${intEq ? 'pass' : 'fail'}">${intEq} ${intEq ? '✓' : '✗'}</span>
    </div>
    <div class="cline">
      <span class="cexpr">(cents/100) === ${raw}</span>
      <span class="cres ${floatEq ? 'pass' : 'fail'}">${floatEq} ${floatEq ? '✓' : '✗'}</span>
    </div>
    <div style="margin-top:6px;color:#555;font-size:0.72rem;">
      Integer cents: ${centsTotal} | Threshold cents: ${threshCents}
    </div>
    <div style="color:#06d6a0;font-size:0.72rem;margin-top:2px;">
      Integer === is always reliable ✓
    </div>
  `;
}

// ─────────────────────────────────────────────
//  THRESHOLD INPUT LISTENERS
// ─────────────────────────────────────────────
document.getElementById('brokenThreshold').addEventListener('input', () => {
  let floatTotal = 0;
  carts.broken.forEach(item => {
    for (let i = 0; i < item.qty; i++) {
      floatTotal += item.priceCents / 100;
    }
  });
  renderBrokenComparisons(floatTotal);
});

document.getElementById('fixedThreshold').addEventListener('input', () => {
  let centsTotal = 0;
  carts.fixed.forEach(item => { centsTotal += item.priceCents * item.qty; });
  renderFixedComparisons(centsTotal);
});

// ─────────────────────────────────────────────
//  INIT
// ─────────────────────────────────────────────
buildFloatGrid();
buildProductButtons();
renderCart('broken');
renderCart('fixed');
</script>
</body>
