];

// ─────────────────────────────────────────────────────────────
//  HELPERS
// ─────────────────────────────────────────────────────────────
const toCents  = (dollars) => Math.round(dollars * 100);
const toDollars = (cents)  => (cents / 100).toFixed(2);

// Show every decimal digit JavaScript actually stores
function fullFloat(n) {
  // toPrecision(20) exposes the hidden digits
  return parseFloat(n.toPrecision(20)).toString();
}

function fmtDollars(n) {
  return "$" + n.toFixed(2);
}

function compRow(expr, value, expected, useColor) {
  const pass = value === expected;
  const cls  = useColor ? (pass ? "PASS" : "FAIL") : "WARN";
  const icon = pass ? "✓" : "✗";
  return `<div class="comp-row">
    <span class="comp-expr">${expr}</span>
    <span class="comp-val ${cls}">${icon} ${String(value)}</span>
  </div>`;
}

// ─────────────────────────────────────────────────────────────
//  BROKEN — float arithmetic
// ─────────────────────────────────────────────────────────────
function buildBroken() {
  const tbody = document.getElementById("broken-tbody");
  tbody.innerHTML = "";

  let floatTotal = 0;

  CART.forEach(item => {
    const lineTotal = item.price * item.qty;   // float multiply
    floatTotal += lineTotal;                    // float add

    const tr = document.createElement("tr");
    tr.innerHTML = `
      <td>${item.name}</td>
      <td>${item.qty}</td>
      <td class="price-col">
        ${fmtDollars(item.price)}
        <span class="raw-float">${fullFloat(item.price)}</span>
      </td>
      <td class="price-col">
        ${fmtDollars(lineTotal)}
        <span class="raw-float">${fullFloat(lineTotal)}</span>
      </td>`;
    tbody.appendChild(tr);
  });

  // Expected total if math were exact
  const expectedTotal = CART.reduce((s, i) => s + i.price * i.qty, 0);
  // toFixed(2) of the float (what the developer "sees")
  const displayedTotal = floatTotal.toFixed(2);

  document.getElementById("broken-total-display").textContent =
    "$" + displayedTotal + " ← toFixed(2) hides the damage";
  document.getElementById("broken-total-raw").textContent =
    "Raw float: " + fullFloat(floatTotal);

  // Comparisons
  const EXPECTED_CENTS = 1047; // $10.47 in cents
  const EXPECTED_FLOAT = 10.47;

  const comps = document.getElementById("broken-comparisons");
  comps.innerHTML = `
    <div class="comp-title">All using === on raw floats</div>
    ${compRow("floatTotal === 10.47",          floatTotal === EXPECTED_FLOAT,  true,  true)}
    ${compRow("floatTotal === " + EXPECTED_FLOAT, floatTotal === EXPECTED_FLOAT, true, true)}
    ${compRow("0.1 + 0.2 === 0.3",             0.1 + 0.2 === 0.3,             true,  true)}
    ${compRow("1.005.toFixed(2) === '1.01'",   (1.005).toFixed(2) === "1.01", true,  true)}
    ${compRow("0.1 + 0.2",                     0.1 + 0.2,                     false, false)}
    ${compRow("floatTotal.toFixed(2) === '10.47'", floatTotal.toFixed(2) === "10.47", true, true)}
  `;

  // Discount
  const DISCOUNT_THRESHOLD = 10.47;
  const exactMatch   = floatTotal === DISCOUNT_THRESHOLD;
  const geCheck      = floatTotal >= DISCOUNT_THRESHOLD;
  const toFixedCheck = floatTotal.toFixed(2) === "10.47";

  document.getElementById("broken-discount").innerHTML = `
    <div class="title">Promo: 10% off when total === $10.47</div>
    <div class="comp-row">
      <span class="comp-expr">floatTotal === 10.47 → discount fires?</span>
