    </div>
    <div class="comp-row">
      <span class="comp-expr">toFixed(2) === "10.47" → string hack, fragile</span>
      <span class="comp-val WARN">${toFixedCheck ? "⚠ works here, fails on 1.005" : "✗ NO"}</span>
    </div>
  `;

  // Explainer
  document.getElementById("broken-explainer").innerHTML = `
    <strong>Why 4.99 cannot be stored exactly in binary:</strong><br>
    4.99 in binary is 100.111111010111000010100011110101110000101000111101…
