  // Comparisons
  const comps = document.getElementById("fixed-comparisons");
  comps.innerHTML = `
    <div class="comp-title">=== on integers — safe because integers are exact</div>
    ${compRow("centsTotal === 1047",     centsTotal === 1047,     true, true)}
