              toCents(0.1) + toCents(0.2) === toCents(0.3),      true, true)}
    ${compRow("toCents(1.005) === 101 (rounds correctly)",
              toCents(1.005) === 101,                             true, true)}
    ${compRow("centsTotal",              centsTotal,              false, false)}
    ${compRow("toDollars(centsTotal)",   toDollars(centsTotal),   false, false)}
  `;

  // Discount
  const DISCOUNT_THRESHOLD_CENTS = 1047;
  const exactMatch = centsTotal === DISCOUNT_THRESHOLD_CENTS;
  const geCheck    = centsTotal >= DISCOUNT_THRESHOLD_CENTS;

  document.getElementById("fixed-discount").innerHTML = `
    <div class="comp-title">Promo: 10% off when total === $10.47 (1047 cents)</div>
    <div class="comp-row">
      <span class="comp-expr">centsTotal === 1047 → discount fires?</span>
