  // Explainer
  document.getElementById("fixed-explainer").innerHTML = `
    <strong style="color:#44ff88">Why integers are exact:</strong><br>
    499, 250, 199, 99 are small whole numbers. Every whole number up to 2⁵³
    (9,007,199,254,740,992) is represented <strong>exactly</strong> in IEEE 754
    double precision — there are no fractional bits to round. Integer addition
    and multiplication on these values produce exact integer results.
    <strong>=== on integers is completely safe.</strong>
    Convert to dollars only at display time using toFixed(2), never for
    computation. This is how every serious financial system works.
  `;
}

