subtotal === ${expectedSubtotal.toFixed(2)} → <span class="${subtotal === expectedSubtotal ? 'pass'>true' : 'fail">false'}</span>
total === recomputedTotal → <span class="${total === recomputedTotal ? 'pass">true' : 'fail">false'}</span>
