// FIXED: integer cents arithmetic
// ═══════════════════════════════════════════════════════════════════════════
function toCents(dollarString) {
  // Parse safely: avoid parseFloat errors by splitting on decimal point
  const str = String(dollarString);
  const parts = str.split('.');
  const dollars = parseInt(parts[0], 10);
  const cents   = parts[1] ? parseInt(parts[1].padEnd(2, '0').slice(0, 2), 10) : 0;
  return dollars * 100 + cents;
}

function formatCents(cents) {
  const sign    = cents < 0 ? '-' : '';
  const abs     = Math.abs(cents);
  const dollars = Math.floor(abs / 100);
  const c       = abs % 100;
  return sign + '$' + dollars + '.' + String(c).padStart(2, '0');
}

// Tax in basis points (1 basis point = 0.01%) to keep integer math
// 8.875% = 8875 basis points
const TAX_BP = 8875;

function fixedCart() {
  const tbody = document.getElementById('fixed-items');
  let subtotalCents = 0;

  CART_ITEMS.forEach(item => {
    const unitCents  = toCents(item.unitPrice);  // exact integer
    const lineCents  = item.qty * unitCents;      // exact integer multiplication
    subtotalCents   += lineCents;                 // exact integer addition
    const tr = document.createElement('tr');
    tr.innerHTML = `
      <td>${item.name}</td>
      <td>${item.qty}</td>
      <td class="price">${formatCents(unitCents)}</td>
      <td class="price">${formatCents(lineCents)}</td>`;
    tbody.appendChild(tr);
  });

  // Tax: multiply then round ONCE — never round intermediate values
  const taxCents   = Math.round(subtotalCents * TAX_BP / 1000000);
  const totalCents = subtotalCents + taxCents;

  document.getElementById('fixed-subtotal').textContent = formatCents(subtotalCents);
  document.getElementById('fixed-tax').textContent      = formatCents(taxCents);
  document.getElementById('fixed-total').textContent    = formatCents(totalCents);

  // Comparisons using === on integers — always correct
  const expectedSubtotalCents = toCents('14.99')*2 + toCents('8.49')*3 +
                                 toCents('6.99')   + toCents('3.49')*4 +
                                 toCents('2.99');
  const expectedTaxCents      = Math.round(expectedSubtotalCents * TAX_BP / 1000000);
  const expectedTotalCents    = expectedSubtotalCents + expectedTaxCents;

  const results = document.getElementById('fixed-results');
  results.innerHTML = `
<span class="dim">// All values are exact integers (cents):</span>
subtotalCents = <span class="pass">${subtotalCents}</span>  <span class="dim">// ${formatCents(subtotalCents)}</span>
taxCents      = <span class="pass">${taxCents}</span>   <span class="dim">// ${formatCents(taxCents)}</span>
totalCents    = <span class="pass">${totalCents}</span>  <span class="dim">// ${formatCents(totalCents)}</span>

<span class="dim">// Equality checks with === on integers:</span>
subtotalCents === ${expectedSubtotalCents} → <span class="${subtotalCents === expectedSubtotalCents ? 'pass">true ✅' : 'fail">false ❌'}</span>
totalCents === ${expectedTotalCents} → <span class="${totalCents === expectedTotalCents ? 'pass">true ✅' : 'fail">false ❌'}</span>
toCents('0.10') + toCents('0.20') === toCents('0.30') → <span class="${toCents('0.10')+toCents('0.20') === toCents('0.30') ? 'pass">true ✅' : 'fail">false ❌'}</span>
<span class="dim">// No rounding surprises, no phantom decimals, no silent failures</span>
`;
}

