    { expr: '(0.1+0.2+0.3) === 0.6',      expected: 'true',    actual: (0.1+0.2+0.3) === 0.6 },
    { expr: 'Math.round(1.255*100)/100',  expected: '1.26',    actual: Math.round(1.255*100)/100 },
    { expr: '6.99 - 0.01',               expected: '6.98',    actual: 6.99 - 0.01 },
