    { expr: '9.99 * 100',                 expected: '999',     actual: 9.99 * 100 },
    { expr: '9.99 * 100 === 999',         expected: 'true',    actual: 9.99 * 100 === 999 },
  ];

  const tbody = document.getElementById('horror-tbody');
  horrors.forEach(h => {
