// IEEE 754 BIT DISPLAY for 4.99
// ═══════════════════════════════════════════════════════════════════════════
function buildBitDisplay() {
  // Get 64-bit representation of 4.99
  const buf   = new ArrayBuffer(8);
  const view  = new DataView(buf);
  view.setFloat64(0, 4.99, false); // big-endian
  let bits = '';
  for (let i = 0; i < 8; i++) {
    bits += view.getUint8(i).toString(2).padStart(8, '0');
  }

  const container = document.getElementById('bit-display');
  const sign     = bits[0];
  const exponent = bits.slice(1, 12);
  const mantissa = bits.slice(12);

  // Sign
  const signGroup = document.createElement('div');
  signGroup.className = 'bit-group';
  signGroup.innerHTML = `<div class="bit-label">S</div><div class="bits"><div class="bit bit-sign">${sign}</div></div>`;
  container.appendChild(signGroup);

  // Exponent — split into chunks for readability
  for (let i = 0; i < 11; i += 4) {
    const chunk = exponent.slice(i, i+4);
    const g = document.createElement('div');
    g.className = 'bit-group';
    g.innerHTML = `<div class="bit-label">E${i}</div><div class="bits">${
      chunk.split('').map(b => `<div class="bit bit-exp">${b}</div>`).join('')
    }</div>`;
    container.appendChild(g);
  }

  // Mantissa — split into chunks
  for (let i = 0; i < 52; i += 4) {
    const chunk = mantissa.slice(i, i+4);
    const g = document.createElement('div');
    g.className = 'bit-group';
    g.innerHTML = `<div class="bit-label">M${i}</div><div class="bits">${
      chunk.split('').map((b,j) => `<div class="bit bit-mantissa${(i+j)%2===0?'':' b1'}">${b}</div>`).join('')
    }</div>`;
    container.appendChild(g);
  }

  const codeEl = document.getElementById('ieee-code');
  const expVal = parseInt(exponent, 2) - 1023;
  codeEl.innerHTML =
`<span class="c-comment">// 4.99 in IEEE 754 double precision:</span>
Bits:     <span style="color:#ff4757">${sign}</span> <span style="color:#ffa502">${exponent}</span> <span style="color:#7474ff">${mantissa.slice(0,26)}</span><span style="color:#5352ed">${mantissa.slice(26)}</span>
Sign:     ${sign === '0' ? 'positive' : 'negative'}
Exponent: ${exponent} (binary) = ${parseInt(exponent,2)} - 1023 = <span style="color:#ffa502">${expVal}</span>
Value:    (-1)^${sign} × 2^${expVal} × 1.${mantissa}₂

<span class="c-comment">// What JavaScript actually stores for 4.99:</span>
(4.99).toFixed(20) = <span class="c-bad">${(4.99).toFixed(20)}</span>
<span class="c-comment">//                      ↑ not 4.99000000000000000000</span>
<span class="c-comment">//  The error is ~4.4 × 10⁻¹⁶ per number.</span>
<span class="c-comment">//  Multiply by 10,000 transactions = $0.0044 unexplained per day.</span>
<span class="c-comment">//  Multiply by 365 days = $1.61 per year per price point.</span>
<span class="c-comment">//  Now multiply by thousands of SKUs. Enjoy your audit.</span>`;
}

