<script>
// ─────────────────────────────────────────────────────────────────────────────
// CART DATA
// ─────────────────────────────────────────────────────────────────────────────
const PRODUCTS = [
  { id: 1, name: "Mechanical Keyboard",  price: 4.99  },
  { id: 2, name: "USB-C Hub",            price: 19.95 },
  { id: 3, name: "Mouse Pad XL",         price: 12.10 },
  { id: 4, name: "Monitor Light Bar",    price: 34.99 },
  { id: 5, name: "Cable Management Kit", price: 8.75  },
];

const TAX_RATE        = 0.0875;   // 8.75%
const DISCOUNT_THRESH = 50.00;    // $50 discount threshold
const FREE_SHIP_CENTS = 7500;     // $75.00 in cents

// Quantities — shared state, both carts use same qty
const qty = { 1: 1, 2: 1, 3: 1, 4: 1, 5: 1 };

// ─────────────────────────────────────────────────────────────────────────────
// SAFE CENT HELPERS
// ─────────────────────────────────────────────────────────────────────────────
const toCents   = (d) => Math.round(d * 100);
const toDisplay = (c) => '$' + (c / 100).toFixed(2);

// ─────────────────────────────────────────────────────────────────────────────
// BROKEN CART — pure float arithmetic
// ─────────────────────────────────────────────────────────────────────────────
function renderBroken() {
  const itemsEl  = document.getElementById('broken-items');
  const totalsEl = document.getElementById('broken-totals');
  const testsEl  = document.getElementById('broken-tests');
  const dumpEl   = document.getElementById('broken-dump');

  itemsEl.innerHTML = '';
  let subtotal = 0;

  PRODUCTS.forEach(p => {
    const q = qty[p.id];
    const lineTotal = p.price * q;   // FLOAT MULTIPLICATION
    subtotal += lineTotal;           // FLOAT ADDITION

    const row = document.createElement('div');
    row.className = 'cart-item';
    row.innerHTML = `
      <span class="item-name">${p.name}</span>
      <span class="item-price">$${p.price.toFixed(2)}</span>
      <span class="item-qty">
        <button onclick="changeQty(${p.id},-1)">−</button>
        <span>${q}</span>
        <button onclick="changeQty(${p.id},+1)">+</button>
      </span>
      <span class="item-subtotal">$${lineTotal.toFixed(2)}</span>
    `;
    itemsEl.appendChild(row);
  });

  const tax      = subtotal * TAX_RATE;   // FLOAT MULTIPLICATION
  const total    = subtotal + tax;        // FLOAT ADDITION
  const discount = subtotal >= DISCOUNT_THRESH ? subtotal * 0.05 : 0;
  const finalTotal = total - discount;

  totalsEl.innerHTML = `
    <div class="total-row"><span class="label">Subtotal (raw float):</span><span style="color:#ff8888">${subtotal}</span></div>
    <div class="total-row"><span class="label">Tax 8.75% (raw float):</span><span style="color:#ff8888">${tax}</span></div>
    <div class="total-row"><span class="label">Discount (raw float):</span><span style="color:#ff8888">${discount}</span></div>
    <div class="total-row grand"><span class="label">TOTAL:</span><span style="color:#ff4444">${finalTotal}</span></div>
    <div class="total-row"><span class="label">toFixed(2) display:</span><span style="color:#ffcc44">$${finalTotal.toFixed(2)}</span></div>
  `;

  // Comparison tests
  const tests = [
    {
      expr: `0.1 + 0.2 === 0.3`,
      result: (0.1 + 0.2) === 0.3,
      expected: true,
      note: `actual: ${0.1 + 0.2}`
    },
    {
      expr: `4.99 + 4.99 === 9.98`,
      result: (4.99 + 4.99) === 9.98,
      expected: true,
      note: `actual: ${4.99 + 4.99}`
    },
    {
      expr: `subtotal === expected`,
      result: (() => {
        let s = 0;
        PRODUCTS.forEach(p => { s += p.price * qty[p.id]; });
        const expected = PRODUCTS.reduce((a, p) => a + p.price * qty[p.id], 0);
        return s === expected;
      })(),
      expected: true,
      note: `raw: ${subtotal}`
    },
    {
      expr: `total.toFixed(2) charged === actual`,
      result: parseFloat(finalTotal.toFixed(2)) === finalTotal,
      expected: true,
      note: `${finalTotal.toFixed(2)} vs ${finalTotal}`
    },
    {
      expr: `subtotal >= $${DISCOUNT_THRESH} threshold`,
      result: subtotal >= DISCOUNT_THRESH,
      expected: null,
      note: `${subtotal} >= ${DISCOUNT_THRESH}`
    },
    {
      expr: `12.10 * 3 === 36.30`,
      result: (12.10 * 3) === 36.30,
      expected: true,
      note: `actual: ${12.10 * 3}`
    },
    {
      expr: `8.75 * 4 === 35.00`,
      result: (8.75 * 4) === 35.00,
      expected: true,
      note: `actual: ${8.75 * 4}`
    },
    {
      expr: `19.95 * 2 === 39.90`,
      result: (19.95 * 2) === 39.90,
      expected: true,
      note: `actual: ${19.95 * 2}`
    },
  ];

  testsEl.innerHTML = tests.map(t => {
    let cls, label;
    if (t.expected === null) {
      cls = 'warn'; label = String(t.result);
    } else if (t.result === t.expected) {
      cls = 'pass'; label = '✓ PASS';
    } else {
      cls = 'fail'; label = '✗ FAIL';
    }
    return `<div class="test-row">
      <span class="test-expr">${t.expr}<br><span style="color:#666;font-size:0.9em">${t.note}</span></span>
      <span class="test-result ${cls}">${label}</span>
    </div>`;
  }).join('');

  // Raw dump
  dumpEl.textContent =
    `BROKEN RAW FLOAT VALUES:\n` +
    `─────────────────────────────────────\n` +
    PRODUCTS.map(p =>
      `${p.name.padEnd(22)} × ${qty[p.id]} = ${(p.price * qty[p.id]).toPrecision(20)}`
    ).join('\n') +
    `\n─────────────────────────────────────\n` +
    `Subtotal : ${subtotal.toPrecision(20)}\n` +
    `Tax      : ${tax.toPrecision(20)}\n` +
    `Discount : ${discount.toPrecision(20)}\n` +
    `Total    : ${finalTotal.toPrecision(20)}\n` +
    `Display  : $${finalTotal.toFixed(2)}\n` +
    `\n⚠ The display looks right. The number is wrong.`;
}

// ─────────────────────────────────────────────────────────────────────────────
// FIXED CART — integer cent arithmetic
// ─────────────────────────────────────────────────────────────────────────────
function renderFixed() {
  const itemsEl  = document.getElementById('fixed-items');
  const totalsEl = document.getElementById('fixed-totals');
  const testsEl  = document.getElementById('fixed-tests');
  const dumpEl   = document.getElementById('fixed-dump');

  itemsEl.innerHTML = '';
  let subtotalCents = 0;

  PRODUCTS.forEach(p => {
    const q           = qty[p.id];
    const priceCents  = toCents(p.price);          // exact integer
    const lineCents   = priceCents * q;             // exact integer multiply
    subtotalCents    += lineCents;                  // exact integer addition

    const row = document.createElement('div');
    row.className = 'cart-item';
    row.innerHTML = `
      <span class="item-name">${p.name}</span>
      <span class="item-price">${toDisplay(priceCents)}</span>
      <span class="item-qty">
        <button onclick="changeQty(${p.id},-1)">−</button>
        <span>${q}</span>
        <button onclick="changeQty(${p.id},+1)">+</button>
      </span>
      <span class="item-subtotal">${toDisplay(lineCents)}</span>
    `;
    itemsEl.appendChild(row);
  });

  // Tax: multiply cents by 875, divide by 10000, round — all integers
  const taxCents      = Math.round(subtotalCents * 875 / 10000);
  const discountCents = subtotalCents >= toCents(DISCOUNT_THRESH)
                        ? Math.round(subtotalCents * 5 / 100)
                        : 0;
  const totalCents    = subtotalCents + taxCents - discountCents;
  const freeShip      = totalCents >= FREE_SHIP_CENTS;

  totalsEl.innerHTML = `
    <div class="total-row"><span class="label">Subtotal (cents):</span><span style="color:#44ff88">${subtotalCents}¢ = ${toDisplay(subtotalCents)}</span></div>
    <div class="total-row"><span class="label">Tax 8.75% (cents):</span><span style="color:#44ff88">${taxCents}¢ = ${toDisplay(taxCents)}</span></div>
    <div class="total-row"><span class="label">Discount (cents):</span><span style="color:#44ff88">${discountCents}¢ = ${toDisplay(discountCents)}</span></div>
    <div class="total-row grand"><span class="label">TOTAL:</span><span style="color:#44ff88">${totalCents}¢ = ${toDisplay(totalCents)}</span></div>
    <div class="total-row"><span class="label">Free shipping:</span><span style="color:${freeShip?'#44ff88':'#ff8888'}">${freeShip ? '✓ YES' : `✗ Need ${toDisplay(FREE_SHIP_CENTS - totalCents)} more`}</span></div>
  `;

  // Comparison tests — all on integers, === is safe
  const p1cents = toCents(4.99);
  const p2cents = toCents(4.99);
  const tests = [
    {
      expr: `toCents(0.1) + toCents(0.2) === toCents(0.3)`,
      result: toCents(0.1) + toCents(0.2) === toCents(0.3),
      expected: true,
      note: `${toCents(0.1)} + ${toCents(0.2)} === ${toCents(0.3)}`
    },
    {
      expr: `499 + 499 === 998`,
      result: p1cents + p2cents === 998,
      expected: true,
      note: `${p1cents} + ${p2cents} = ${p1cents + p2cents}`
    },
    {
      expr: `subtotalCents === recomputed`,
      result: (() => {
        let s = 0;
        PRODUCTS.forEach(p => { s += toCents(p.price) * qty[p.id]; });
        return s === subtotalCents;
      })(),
      expected: true,
      note: `${subtotalCents}¢`
    },
    {
      expr: `displayed total === charged total`,
      result: parseInt((totalCents / 100).toFixed(2).replace('.','')) === totalCents,
      expected: true,
      note: `${toDisplay(totalCents)} is exactly ${totalCents}¢`
    },
    {
      expr: `subtotalCents >= discount threshold`,
      result: subtotalCents >= toCents(DISCOUNT_THRESH),
      expected: null,
      note: `${subtotalCents}¢ >= ${toCents(DISCOUNT_THRESH)}¢`
    },
    {
      expr: `toCents(12.10) * 3 === 3630`,
      result: toCents(12.10) * 3 === 3630,
      expected: true,
      note: `${toCents(12.10)} × 3 = ${toCents(12.10) * 3}`
    },
    {
      expr: `toCents(8.75) * 4 === 3500`,
      result: toCents(8.75) * 4 === 3500,
      expected: true,
      note: `${toCents(8.75)} × 4 = ${toCents(8.75) * 4}`
    },
    {
      expr: `toCents(19.95) * 2 === 3990`,
      result: toCents(19.95) * 2 === 3990,
      expected: true,
      note: `${toCents(19.95)} × 2 = ${toCents(19.95) * 2}`
    },
  ];

  testsEl.innerHTML = tests.map(t => {
    let cls, label;
    if (t.expected === null) {
      cls = 'warn'; label = String(t.result);
    } else if (t.result === t.expected) {
      cls = 'pass'; label = '✓ PASS';
    } else {
      cls = 'fail'; label = '✗ FAIL';
    }
    return `<div class="test-row">
      <span class="test-expr">${t.expr}<br><span style="color:#666;font-size:0.9em">${t.note}</span></span>
      <span class="test-result ${cls}">${label}</span>
    </div>`;
  }).join('');

  dumpEl.textContent =
    `FIXED INTEGER CENT VALUES:\n` +
    `─────────────────────────────────────\n` +
    PRODUCTS.map(p => {
      const c = toCents(p.price) * qty[p.id];
      return `${p.name.padEnd(22)} × ${qty[p.id]} = ${c}¢ (exact)`;
    }).join('\n') +
    `\n─────────────────────────────────────\n` +
    `Subtotal : ${subtotalCents}¢\n` +
    `Tax      : ${taxCents}¢\n` +
    `Discount : ${discountCents}¢\n` +
    `Total    : ${totalCents}¢\n` +
    `Display  : ${toDisplay(totalCents)}\n` +
    `\n✓ Display and charged amount are identical.`;
}

// ─────────────────────────────────────────────────────────────────────────────
// BIT PATTERN TABLE
// ─────────────────────────────────────────────────────────────────────────────
function floatToBits(f) {
  const buf = new ArrayBuffer(8);
  new Float64Array(buf)[0] = f;
  const bytes = new Uint8Array(buf);
  let bits = '';
  for (let i = 7; i >= 0; i--) {
    bits += bytes[i].toString(2).padStart(8, '0');
  }
  return bits;
}

function renderBitTable() {
  const values = [0.1, 0.2, 0.3, 4.99, 9.98, 19.95, 12.10, 8.75, 34.99];
  const tbody = document.getElementById('bit-tbody');
  tbody.innerHTML = values.map(v => {
    const bits    = floatToBits(v);
    const actual  = new Float64Array(new ArrayBuffer(8));
    const buf     = new ArrayBuffer(8);
    new Float64Array(buf)[0] = v;
    const stored  = new Float64Array(buf)[0];
    const error   = stored - v;
    const sign    = bits[0];
    const exp     = bits.slice(1, 12);
    const mant    = bits.slice(12);
    const colored = `<span style="color:#ff6666">${sign}</span><span style="color:#ffcc44">${exp}</span><span style="color:#88aaff">${mant}</span>`;
    return `<tr>
      <td style="color:#fff">${v}</td>
      <td style="color:#ff8888;font-size:0.8em">${stored.toPrecision(20)}</td>
      <td style="color:${error===0?'#44ff88':'#ff4444'}">${error === 0 ? '0 (exact)' : error.toExponential(4)}</td>
      <td class="bits">${colored}</td>
    </tr>`;
  }).join('');
}

// ─────────────────────────────────────────────────────────────────────────────
// QUANTITY CONTROLS
// ─────────────────────────────────────────────────────────────────────────────
function changeQty(id, delta) {
  qty[id] = Math.max(1, (qty[id] || 1) + delta);
  renderAll();
}

function renderAll() {
  renderBroken();
  renderFixed();
}

// ─────────────────────────────────────────────────────────────────────────────
// INIT
// ─────────────────────────────────────────────────────────────────────────────
renderAll();
renderBitTable();
</script>
</body>
</html>
